// Use pdf_texts_extracted (actual PDF docs with requirements) instead of pdf_text (GAEB BoQ)
const tender = $('load-tender').first().json;
const pdfTexts = tender.pdf_texts_extracted;
let extractionText = '';
if (pdfTexts) {
  if (Array.isArray(pdfTexts)) {
    extractionText = pdfTexts.map((t, i) => '=== Dokument ' + (i+1) + ' ===
' + (t || '')).join('

').slice(0, 12000);
  } else if (typeof pdfTexts === 'object') {
    extractionText = Object.entries(pdfTexts).map(([k, v]) => '=== ' + k + ' ===
' + (v || '')).join('

').slice(0, 12000);
  } else {
    extractionText = String(pdfTexts).slice(0, 12000);
  }
}
if (!extractionText && tender.pdf_text) {
  extractionText = tender.pdf_text.slice(0, 12000);
}
// Last resort: if still empty, seed with structural info so AI isn't flying blind.
// Use title, raw_gaeb_json error diagnostics, and archive folder names.
if (!extractionText || extractionText.trim().length < 50) {
  const lines = [];
  if (tender.title && tender.title !== 'Leistungsverzeichnis') lines.push('Projekttitel: ' + tender.title);
  const gaebFiles = tender.raw_gaeb_json || [];
  for (const g of gaebFiles) {
    if (g._error && typeof g._error === 'string') {
      // Extract the "Other:" section which lists GAEB file paths with descriptive folder names
      const otherMatch = g._error.match(/Other: \[([^\]]+)\]/);
      if (otherMatch) {
        const paths = otherMatch[1].split(', ');
        const folders = new Set();
        for (const p of paths) {
          const parts = p.split('/');
          if (parts.length >= 3) folders.add(parts[parts.length - 2]);
        }
        if (folders.size > 0) lines.push('Teilleistungen: ' + Array.from(folders).join(', '));
      }
      // Extract PDF names that look like LV documents
      const pdfMatch = g._error.match(/PDFs: \[([^\]]+)\]/);
      if (pdfMatch) {
        const pdfs = pdfMatch[1].split(', ')
          .map(p => p.split('/').pop())
          .filter(n => /lv|leistung|ausschreib|verzeichnis/i.test(n))
          .slice(0, 5);
        if (pdfs.length > 0) lines.push('Dokumente: ' + pdfs.join(', '));
      }
    }
  }
  if (lines.length > 0) extractionText = lines.join('
');
}
return [{ json: { ...tender, extraction_text: extractionText } }];

const content = $json.choices[0].message.content;
let requirements = [];
try {
  const cleaned = content.replace(/```json/g, '').replace(/```/g, '').trim();
  const parsed = JSON.parse(cleaned);
  // Handle both array (new format) and object with requirements key (legacy)
  requirements = Array.isArray(parsed) ? parsed : (parsed.requirements || []);
} catch (e) {
  console.error('Failed to parse requirements:', e);
}
return [{ json: { requirements } }];

